package com.google.gson;

import static org.junit.jupiter.api.Assertions.assertEquals;

import com.google.gson.internal.ConstructorConstructor;
import com.google.gson.internal.bind.JsonAdapterAnnotationTypeAdapterFactory;
import com.google.gson.internal.bind.TypeAdapterFactory;
import com.google.gson.reflect.TypeToken;
import java.lang.reflect.Field;
import java.lang.reflect.Type;
import java.util.Collections;
import java.util.List;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.ConcurrentMap;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.Objects;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class GsonToStringTest {

  private Gson gson;

  @BeforeEach
  void setUp() throws Exception {
    // Prepare instanceCreators map with correct generic type and parameters
    Map<Type, InstanceCreator<?>> instanceCreators = new HashMap<>();

    // Prepare constructorConstructor with required parameters:
    // Map<Type, InstanceCreator<?>>, boolean, List<ReflectionAccessFilter>
    // For boolean and List<ReflectionAccessFilter>, use false and empty list
    ConstructorConstructor constructorConstructor =
        new ConstructorConstructor(instanceCreators, false, Collections.emptyList());

    // Prepare factories list (empty)
    List<TypeAdapterFactory> factories = Collections.emptyList();

    // Prepare jsonAdapterFactory
    JsonAdapterAnnotationTypeAdapterFactory jsonAdapterFactory =
        new JsonAdapterAnnotationTypeAdapterFactory(constructorConstructor);

    // Create Gson instance using the constructor with all parameters
    gson = new Gson(
        new com.google.gson.internal.Excluder(),
        com.google.gson.FieldNamingPolicy.IDENTITY,
        instanceCreators,
        true, // serializeNulls
        false, // complexMapKeySerialization
        false, // generateNonExecutableGson
        true, // htmlSafe
        false, // prettyPrinting
        false, // lenient
        false, // serializeSpecialFloatingPointValues
        true, // useJdkUnsafe
        LongSerializationPolicy.DEFAULT,
        null, // datePattern
        2, // dateStyle
        2, // timeStyle
        Collections.emptyList(), // builderFactories
        Collections.emptyList(), // builderHierarchyFactories
        factories, // factoriesToBeAdded
        com.google.gson.ToNumberPolicy.DOUBLE,
        com.google.gson.ToNumberPolicy.LAZILY_PARSED_NUMBER,
        Collections.emptyList() // reflectionFilters
    );

    // Use reflection to set private final fields that are not set by constructor or to override
    setField(gson, "serializeNulls", true);
    setField(gson, "factories", factories);
    setField(gson, "constructorConstructor", constructorConstructor);
  }

  @Test
  void testToString_containsSerializeNullsFactoriesAndConstructorConstructor() {
    String result = gson.toString();

    // Expected string format:
    // {serializeNulls:true,factories:[],instanceCreators:com.google.gson.internal.ConstructorConstructor@...}
    // We check startsWith and contains to avoid depending on exact hashcode
    String expectedStart = "{serializeNulls:true,factories:";

    // Check start
    assertEquals(true, result.startsWith(expectedStart));

    // Check factories string representation
    assertEquals(true, result.contains("factories:[]"));

    // Check instanceCreators contains ConstructorConstructor class name
    assertEquals(true, result.contains("instanceCreators:com.google.gson.internal.ConstructorConstructor"));
  }

  private static void setField(Object target, String fieldName, Object value) throws Exception {
    Field field = Gson.class.getDeclaredField(fieldName);
    field.setAccessible(true);

    // Remove final modifier if present (for Java 12+)
    Field modifiersField = Field.class.getDeclaredField("modifiers");
    modifiersField.setAccessible(true);
    modifiersField.setInt(field, field.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

    field.set(target, value);
  }
}
